#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <semaphore.h>
#include <unistd.h>

#define BUFFER_SIZE 5
#define NUM_ITEMS 10

// Shared buffer
int buffer[BUFFER_SIZE];
int in = 0; // Producer index
int out = 0; // Consumer index

// Semaphores and mutex
sem_t empty; // Counting semaphore for empty slots
sem_t full; // Counting semaphore for full slots
pthread_mutex_t mutex; // Mutual exclusion lock

// Counter for produced items
int item_counter = 0;

void* producer(void* arg) {
 int producer_id = *(int*)arg;

 for (int i = 0; i < NUM_ITEMS; i++) {
 int item = item_counter++;

 sem_wait(&empty); // Wait for empty slot
 pthread_mutex_lock(&mutex); // Enter critical section

 buffer[in] = item;
 printf("Producer %d produced: %d (in=%d)\n", producer_id, item, in);
 in = (in + 1) % BUFFER_SIZE;

 pthread_mutex_unlock(&mutex); // Exit critical section
 sem_post(&full); // Signal full slot

 sleep(1); // Simulate production time
 }
 return NULL;
}

void* consumer(void* arg) {
 int consumer_id = *(int*)arg;

 for (int i = 0; i < NUM_ITEMS; i++) {
 sem_wait(&full); // Wait for full slot
 pthread_mutex_lock(&mutex); // Enter critical section

 int item = buffer[out];
 printf("Consumer %d consumed: %d (out=%d)\n", consumer_id, item, out);
 out = (out + 1) % BUFFER_SIZE;

 pthread_mutex_unlock(&mutex); // Exit critical section
 sem_post(&empty); // Signal empty slot

 sleep(1); // Simulate consumption time
 }
 return NULL;
}

int main() {
 pthread_t producers[2], consumers[2];
 int producer_ids[2] = {1, 2};
 int consumer_ids[2] = {1, 2};

 // Initialize semaphores and mutex
 sem_init(&empty, 0, BUFFER_SIZE);
 sem_init(&full, 0, 0);
 pthread_mutex_init(&mutex, NULL);

 // Create producer threads
 for (int i = 0; i < 2; i++) {
 pthread_create(&producers[i], NULL, producer, &producer_ids[i]);
 }

 // Create consumer threads
 for (int i = 0; i < 2; i++) {
 pthread_create(&consumers[i], NULL, consumer, &consumer_ids[i]);
 }

 // Wait for all threads to complete
 for (int i = 0; i < 2; i++) {
 pthread_join(producers[i], NULL);
 pthread_join(consumers[i], NULL);
 }

 // Cleanup
 sem_destroy(&empty);
 sem_destroy(&full);
 pthread_mutex_destroy(&mutex);

 printf("All items produced and consumed.\n");
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <semaphore.h>
#include <unistd.h>

#define NUM_PHILOSOPHERS 5

// Chopstick semaphores
sem_t chopsticks[NUM_PHILOSOPHERS];

// For state tracking
enum { THINKING, HUNGRY, EATING } state[NUM_PHILOSOPHERS];
pthread_mutex_t mutex; // Protects state array

// Helper function declarations
void test(int philosopher_id);
void pickup_forks(int philosopher_id);
void return_forks(int philosopher_id);
void* philosopher(void* arg);

void test(int i) {
 // Philosopher i can eat if:
 // - HUNGRY and
 // - Left neighbor not eating and
 // - Right neighbor not eating
 int left = (i + NUM_PHILOSOPHERS - 1) % NUM_PHILOSOPHERS;
 int right = (i + 1) % NUM_PHILOSOPHERS;

 if (state[i] == HUNGRY && 
 state[left] != EATING && 
 state[right] != EATING) {
 state[i] = EATING;
 sem_post(&chopsticks[i]); // Allow philosopher to eat
 }
}

void pickup_forks(int i) {
 pthread_mutex_lock(&mutex);
 state[i] = HUNGRY;
 printf("Philosopher %d is HUNGRY\n", i);
 test(i); // Try to acquire forks
 pthread_mutex_unlock(&mutex);

 sem_wait(&chopsticks[i]); // Wait until forks available
 usleep(100000); // Small delay for state update
}

void return_forks(int i) {
 pthread_mutex_lock(&mutex);
 state[i] = THINKING;
 printf("Philosopher %d is THINKING\n", i);

 // Check if neighbors can now eat
 int left = (i + NUM_PHILOSOPHERS - 1) % NUM_PHILOSOPHERS;
 int right = (i + 1) % NUM_PHILOSOPHERS;
 test(left);
 test(right);

 pthread_mutex_unlock(&mutex);
}

void* philosopher(void* arg) {
 int id = *(int*)arg;

 while (1) {
 printf("Philosopher %d is THINKING\n", id);
 sleep(1 + rand() % 2); // Thinking time

 pickup_forks(id);
 printf("Philosopher %d is EATING\n", id);
 sleep(1 + rand() % 2); // Eating time
 return_forks(id);
 }
 return NULL;
}

int main() {
 pthread_t threads[NUM_PHILOSOPHERS];
 int ids[NUM_PHILOSOPHERS];

 // Initialize semaphores and mutex
 pthread_mutex_init(&mutex, NULL);
 for (int i = 0; i < NUM_PHILOSOPHERS; i++) {
 sem_init(&chopsticks[i], 0, 0);
 state[i] = THINKING;
 ids[i] = i;
 }

 srand(time(NULL));

 // Create philosopher threads
 for (int i = 0; i < NUM_PHILOSOPHERS; i++) {
 pthread_create(&threads[i], NULL, philosopher, &ids[i]);
 }

 // Let philosophers run for a while
 sleep(30);

 printf("Simulation ended.\n");
 return 0;
}
